Here is how you can modify `FirebaseAuthUtil` to include Google Sign-In functionality:

```java
package com.HidiStudios.BeST.Utilities;

// ... other imports
import com.google.firebase.auth.GoogleAuthProvider;
import com.google.firebase.auth.AuthCredential;
import com.google.android.gms.auth.api.signin.GoogleSignIn;
import com.google.android.gms.auth.api.signin.GoogleSignInAccount;
import com.google.android.gms.auth.api.signin.GoogleSignInOptions;
import com.google.android.gms.common.api.ApiException;
import com.google.firebase.auth.FirebaseAuthUserCollisionException;

public class FirebaseAuthUtil {
    public static FirebaseAuth mAuth;
    private static GoogleSignInClient mGoogleSignInClient;

    // ... other methods ...

    public static void initializeGoogleSignIn(Context context, String defaultWebClientId) {
        GoogleSignInOptions gso = new GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_SIGN_IN)
                .requestIdToken(defaultWebClientId)
                .requestEmail()
                .build();

        mGoogleSignInClient = GoogleSignIn.getClient(context, gso);
    }

    public static Intent getGoogleSignInIntent() {
        if (mGoogleSignInClient == null) {
            return null;
        }
        return mGoogleSignInClient.getSignInIntent();
    }

    public static void handleGoogleSignInResult(Intent data, final OnGoogleSignInCompleteListener listener) {
        Task<GoogleSignInAccount> task = GoogleSignIn.getSignedInAccountFromIntent(data);
        try {
            // Google Sign In was successful, authenticate with Firebase
            GoogleSignInAccount account = task.getResult(ApiException.class);

            AuthCredential credential = GoogleAuthProvider.getCredential(account.getIdToken(), null);
            FirebaseUser currentUser = mAuth.getCurrentUser();

            if (currentUser != null) {
                currentUser.linkWithCredential(credential)
                        .addOnCompleteListener(task1 -> {
                            if (task1.isSuccessful()) {
                                // ... Callback success with FirebaseUser ...
                                listener.onGoogleSignInComplete(task1.getResult().getUser(), false);
                            } else {
                                Exception e = task1.getException();
                                if (e instanceof FirebaseAuthUserCollisionException) {
                                    // ... Callback for collision ...
                                    listener.onGoogleSignInCollision(credential);
                                } else {
                                    listener.onGoogleSignInFailed(e);
                                }
                            }
                        });
            }
        } catch (ApiException e) {
            listener.onGoogleSignInFailed(e);
        }
    }

    // signInWithCredential logic ported as-is with slight modifications for static context
    public static void signInWithCredential(AuthCredential credential, final OnGoogleSignInCompleteListener listener) {
        mAuth.signInWithCredential(credential).addOnCompleteListener(task -> {
            if (task.isSuccessful()) {
                // ... Callback success ...
                listener.onGoogleSignInComplete(task.getResult().getUser(), true);
            } else {
                Exception e = task.getException();
                listener.onGoogleSignInFailed(e);
            }
        });
    }

    // ... Other methods, such as saveToDB ...

    public interface OnGoogleSignInCompleteListener {
        void onGoogleSignInComplete(FirebaseUser user, boolean isNewUser);
        void onGoogleSignInCollision(AuthCredential credential);
        void onGoogleSignInFailed(Exception e);
    }
}
```

